      out.write("    menu_RECEPCIONISTA:[{l:'📋 Check appointment',id:'consultar_cita'},{l:'👥 Patient management',id:'guia_pacientes'},{l:'📅 Appointment management',id:'guia_citas'},{l:'🏥 Services',id:'servicios'},{l:'📞 Contact',id:'contacto'}],\n");
