      out.write("    volver:'↩ Back to menu',\n");
      out.write("    no_entiendo:'🤔 I didn\\'t understand that. Please choose an option:',\n");
      out.write("    servicios:'🏥 **Our services:**\\n\\n🩺 **General Medicine** — Care for the whole family\\n👶 **Pediatrics** — Children and adolescent care\\n👩‍⚕️ **Gynecology** — Women\\'s health\\n🦷 **Dentistry** — Oral health\\n👁️ **Optometry** — Eye exams\\n📄 **Medical Certificates** — Receipts and certificates',\n");
      out.write("    horarios:'🕐 **Attendance schedules:**\\n\\n📅 Monday to Friday\\n🕖 Morning: 7:00 AM – 12:00 PM\\n🕑 Afternoon: 2:00 PM – 5:00 PM\\n\\n_For a specific doctor\\'s schedule, check the **Schedules** section._',\n");
      out.write("    como_sacar:'📝 **How to book an appointment?**\\n\\n**Registered patient:**\\n1️⃣ Log in\\n2️⃣ Menu → Appointments → New Appointment\\n3️⃣ Select specialty, doctor and date\\n4️⃣ Confirm and download your PDF\\n\\n**New patient:**\\n1️⃣ Visit the reception\\n2️⃣ Receptionist will register you\\n3️⃣ Then manage appointments online',\n");
      out.write("    contacto:'📞 **Contact**\\n\\n🏥 Municipal Health Center of Paipa, Boyacá\\n📍 Paipa, Boyacá, Colombia\\n🕐 Mon–Fri: 7:00 AM – 5:00 PM\\n\\n🎓 _SENA · CIMM · Regional Boyacá · 2026_',\n");
      out.write("    guia_pacientes:'👥 **Patient Management (Receptionist)**\\n\\n➕ New: Menu → Patients → New Patient\\n✏️ Edit: List → click ✏️\\n🗑️ Delete: Only Receptionist\\n🔍 Search: By name, ID or insurance\\n📸 Photo: JPG/PNG max 2 MB',\n");
      out.write("    guia_citas:'📅 **Appointment Management (Receptionist)**\\n\\n➕ New: Menu → Appointments → New\\n  1. Patient → 2. Specialty → doctor → date\\n  3. System validates availability automatically\\n\\n✏️ Edit: only *Scheduled* appointments\\n📄 PDF: from appointment detail',\n");
      out.write("    estados_cita:'🔄 **Appointment statuses (Doctor)**\\n\\n🟡 **Scheduled** → Confirm or Cancel\\n🟢 **Confirmed** → Mark as Attended\\n✅ **Attended** → Final status\\n🔴 **Cancelled** → Final status\\n\\n_From: Appointments → View detail_',\n");
      out.write("    citas_dia:'📅 To see today\\'s appointments:\\n\\n**Menu → Medical Appointments**\\n\\n🟢 Filter **\"Confirmed\"** → ready to attend\\n🟡 Filter **\"Scheduled\"** → pending confirmation'\n");
      out.write("  },\n");
      out.write("  it:{\n");
      out.write("    status:'● Online', placeholder:'Scrivi qualcosa...',\n");
      out.write("    bienvenida_PUBLICO:'Ciao! 👋 Sono **Kira**, l\\'assistente virtuale di **SaludBoyacá**.\\n\\nCome posso aiutarti oggi?',\n");
      out.write("    bienvenida_RECEPCIONISTA:'Ciao, {n}! 👋 Sono **Kira**.\\nSei connesso come **Receptionist**. Come posso aiutarti?',\n");
      out.write("    bienvenida_MEDICO:'Benvenuto/a, Dott. **{n}** 👋 Sono **Kira**.\\nSei come **Medico**. Cosa ti serve?',\n");
      out.write("    bienvenida_ENFERMERO:'Ciao, **{n}**! 👋 Sono **Kira**.\\nSei come **Infermiere/a**. Come posso assisterti?',\n");
      out.write("    menu_PUBLICO:[{l:'📋 Controlla appuntamento',id:'consultar_cita'},{l:'🏥 Servizi',id:'servicios'},{l:'🕐 Orari medici',id:'horarios'},{l:'📝 Come prenotare?',id:'como_sacar'},{l:'📞 Contatto',id:'contacto'}],\n");
      out.write("    menu_RECEPCIONISTA:[{l:'📋 Controlla appuntamento',id:'consultar_cita'},{l:'👥 Gestione pazienti',id:'guia_pacientes'},{l:'📅 Gestione appuntamenti',id:'guia_citas'},{l:'🏥 Servizi',id:'servicios'},{l:'📞 Contatto',id:'contacto'}],\n");
      out.write("    menu_MEDICO:[{l:'📋 Controlla appuntamento',id:'consultar_cita'},{l:'📅 Appuntamenti oggi',id:'citas_dia'},{l:'🔄 Stati appuntamento',id:'estados_cita'},{l:'🕐 Orari',id:'horarios'},{l:'📞 Contatto',id:'contacto'}],\n");
      out.write("    menu_ENFERMERO:[{l:'📋 Controlla appuntamento',id:'consultar_cita'},{l:'🏥 Servizi',id:'servicios'},{l:'🕐 Orari',id:'horarios'},{l:'📞 Contatto',id:'contacto'}],\n");
      out.write("    pedir_doc:'🔍 Inserisci il **numero documento** del paziente:',\n");
      out.write("    doc_invalido:'⚠️ Il documento deve avere tra 5 e 15 cifre numeriche. Riprova.',\n");
      out.write("    doc_ok:'✅ Documento **{d}** ricevuto.\\n\\nPer controllare lo stato reale vai a:\\n📋 **Menu → Ricerca Appuntamento**\\no accedi al sistema.',\n");
      out.write("    volver:'↩ Torna al menu',\n");
      out.write("    no_entiendo:'🤔 Non ho capito. Scegli un\\'opzione:',\n");
      out.write("    servicios:'🏥 **I nostri servizi:**\\n\\n🩺 **Medicina Generale** — Assistenza per tutta la famiglia\\n👶 **Pediatria** — Cura bambini e adolescenti\\n👩‍⚕️ **Ginecologia** — Salute della donna\\n🦷 **Odontoiatria** — Salute orale\\n👁️ **Optometria** — Esami della vista\\n📄 **Certificati Medici** — Ricevute e certificati',\n");
      out.write("    horarios:'🕐 **Orari di attenzione:**\\n\\n📅 Lunedì–Venerdì\\n🕖 Mattina: 7:00 – 12:00\\n🕑 Pomeriggio: 14:00 – 17:00\\n\\n_Per l\\'orario di un medico specifico consulta la sezione **Orari**._',\n");
      out.write("    como_sacar:'📝 **Come prenotare un appuntamento?**\\n\\n**Paziente registrato:**\\n1️⃣ Accedi\\n2️⃣ Menu → Appuntamenti → Nuovo\\n3️⃣ Seleziona specialità, medico e data\\n4️⃣ Conferma e scarica il PDF\\n\\n**Nuovo paziente:**\\n1️⃣ Vai alla reception\\n2️⃣ Il receptionist ti registrerà\\n3️⃣ Poi gestisci online',\n");
      out.write("    contacto:'📞 **Contatto**\\n\\n🏥 Centro Salute Municipale di Paipa, Boyacá\\n📍 Paipa, Boyacá, Colombia\\n🕐 Lun–Ven: 7:00 – 17:00\\n\\n🎓 _SENA · CIMM · Regional Boyacá · 2026_',\n");
      out.write("    guia_pacientes:'👥 **Gestione Pazienti (Receptionist)**\\n\\n➕ Nuovo: Menu → Pazienti → Nuovo Paziente\\n✏️ Modifica: Lista → clicca ✏️\\n🗑️ Elimina: Solo Receptionist\\n🔍 Cerca: Per nome, documento o assicurazione\\n📸 Foto: JPG/PNG max 2 MB',\n");
      out.write("    guia_citas:'📅 **Gestione Appuntamenti (Receptionist)**\\n\\n➕ Nuovo: Menu → Appuntamenti → Nuovo\\n  1. Paziente → 2. Specialità → medico → data\\n  3. Il sistema verifica disponibilità automaticamente\\n\\n✏️ Modifica: solo *Programmati*\\n📄 PDF: dal dettaglio appuntamento',\n");
      out.write("    estados_cita:'🔄 **Stati appuntamento (Medico)**\\n\\n🟡 **Programmata** → Confermare o Cancellare\\n🟢 **Confermata** → Marcare come Visitata\\n✅ **Visitata** → Stato finale\\n🔴 **Cancellata** → Stato finale\\n\\n_Da: Appuntamenti → Vedi dettaglio_',\n");
      out.write("    citas_dia:'📅 Per vedere gli appuntamenti di oggi:\\n\\n**Menu → Appuntamenti Medici**\\n\\n🟢 Filtro **\"Confermata\"** → pronti per oggi\\n🟡 Filtro **\"Programmata\"** → in attesa di conferma'\n");
      out.write("  }\n");
      out.write("};\n");
      out.write("\n");
      out.write("/* ── Helpers ── */\n");
      out.write("function kEl(id){ return document.getElementById(id); }\n");
      out.write("function kT(key){\n");
      out.write("  var d = KIRA_T[KIRA.lang] || KIRA_T.es;\n");
      out.write("  return d[key] !== undefined ? d[key] : (KIRA_T.es[key] || '');\n");
      out.write("}\n");
      out.write("function kMenu(){\n");
      out.write("  var d = KIRA_T[KIRA.lang] || KIRA_T.es;\n");
      out.write("  return d['menu_'+KIRA.rol] || d.menu_PUBLICO || [];\n");
      out.write("}\n");
      out.write("function kBienvenida(){\n");
      out.write("  var txt = kT('bienvenida_'+KIRA.rol) || kT('bienvenida_PUBLICO');\n");
      out.write("  return txt.replace(/{n}/g, KIRA.nombre || '');\n");
      out.write("}\n");
      out.write("function kMd(t){\n");
      out.write("  return t.replace(/\\*\\*(.+?)\\*\\*/g,'<strong>$1</strong>')\n");
      out.write("          .replace(/\\*(.+?)\\*/g,'<em>$1</em>')\n");
      out.write("          .replace(/\\n/g,'<br>');\n");
      out.write("}\n");
      out.write("\n");
      out.write("var KIRA_ICON = '<svg viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M12 2C9.243 2 7 4.243 7 7s2.243 5 5 5 5-2.243 5-5-2.243-5-5-5zM12 10c-1.654 0-3-1.346-3-3s1.346-3 3-3 3 1.346 3 3-1.346 3-3 3zM21 21v-1c0-3.859-3.141-7-7-7h-4c-3.859 0-7 3.141-7 7v1h2v-1c0-2.757 2.243-5 5-5h4c2.757 0 5 2.243 5 5v1h2zM16 11h2v2h2v2h-2v2h-2v-2h-2v-2h2z\"/></svg>';\n");
      out.write("\n");
      out.write("function kAddMsg(txt, who){\n");
      out.write("  var msgs = kEl('kira-messages');\n");
      out.write("  var wrap = document.createElement('div');\n");
      out.write("  wrap.className = 'kira-msg kira-'+who;\n");
      out.write("  var av = document.createElement('div');\n");
      out.write("  av.className = 'kira-msg-av';\n");
      out.write("  if(who==='bot'){ av.innerHTML = KIRA_ICON; }\n");
      out.write("  else { av.textContent = KIRA.nombre ? KIRA.nombre.charAt(0).toUpperCase() : '?'; }\n");
      out.write("  var bub = document.createElement('div');\n");
      out.write("  bub.className = 'kira-bubble';\n");
      out.write("  bub.innerHTML = kMd(txt);\n");
      out.write("  wrap.appendChild(av); wrap.appendChild(bub);\n");
      out.write("  msgs.appendChild(wrap);\n");
      out.write("  msgs.scrollTop = msgs.scrollHeight;\n");
      out.write("}\n");
      out.write("\n");
      out.write("function kShowTyping(){\n");
      out.write("  var msgs = kEl('kira-messages');\n");
      out.write("  var wrap = document.createElement('div');\n");
      out.write("  wrap.className = 'kira-msg kira-bot'; wrap.id = 'kira-ty';\n");
      out.write("  var av = document.createElement('div'); av.className='kira-msg-av'; av.innerHTML=KIRA_ICON;\n");
      out.write("  var dot = document.createElement('div'); dot.className='kira-typing';\n");
      out.write("  dot.innerHTML='<span></span><span></span><span></span>';\n");
      out.write("  wrap.appendChild(av); wrap.appendChild(dot);\n");
      out.write("  msgs.appendChild(wrap); msgs.scrollTop = msgs.scrollHeight;\n");
      out.write("}\n");
      out.write("function kHideTyping(){ var e=kEl('kira-ty'); if(e) e.remove(); }\n");
      out.write("\n");
      out.write("function kSetChips(items){\n");
      out.write("  var c = kEl('kira-chips'); c.innerHTML='';\n");
      out.write("  if(!items||!items.length) return;\n");
      out.write("  items.forEach(function(item){\n");
      out.write("    var btn = document.createElement('button');\n");
      out.write("    btn.className='kira-chip'; btn.textContent=item.l;\n");
      out.write("    btn.addEventListener('click', function(){ kHandle(item.id, item.l); });\n");
      out.write("    c.appendChild(btn);\n");
      out.write("  });\n");
      out.write("}\n");
      out.write("\n");
      out.write("function kReply(txt, delay, chips){\n");
      out.write("  kShowTyping();\n");
      out.write("  setTimeout(function(){\n");
      out.write("    kHideTyping(); kAddMsg(txt,'bot'); kSetChips(chips||[]);\n");
      out.write("  }, delay||700);\n");
      out.write("}\n");
      out.write("\n");
      out.write("/* ── Flujos ── */\n");
      out.write("function kHandle(id, label){\n");
      out.write("  kAddMsg(label,'user'); kSetChips([]); KIRA.state='menu';\n");
      out.write("  var back = [{l:kT('volver'), id:'volver_menu'}];\n");
      out.write("  switch(id){\n");
      out.write("    case 'consultar_cita': kReply(kT('pedir_doc'),500); KIRA.state='esperando_doc'; break;\n");
      out.write("    case 'servicios':      kReply(kT('servicios'),600,back); break;\n");
      out.write("    case 'horarios':       kReply(kT('horarios'),600,back); break;\n");
      out.write("    case 'como_sacar':     kReply(kT('como_sacar'),600,back); break;\n");
      out.write("    case 'contacto':       kReply(kT('contacto'),600,back); break;\n");
      out.write("    case 'guia_pacientes': kReply(kT('guia_pacientes'),600,back); break;\n");
      out.write("    case 'guia_citas':     kReply(kT('guia_citas'),600,back); break;\n");
      out.write("    case 'estados_cita':   kReply(kT('estados_cita'),600,back); break;\n");
      out.write("    case 'citas_dia':      kReply(kT('citas_dia'),600,back); break;\n");
      out.write("    case 'volver_menu': case 'menu': kShowMenu(); break;\n");
      out.write("    default: kReply(kT('no_entiendo'),500,kMenu());\n");
      out.write("  }\n");
      out.write("}\n");
      out.write("\n");
      out.write("function kShowMenu(){\n");
      out.write("  KIRA.state='menu';\n");
      out.write("  kShowTyping();\n");
      out.write("  setTimeout(function(){ kHideTyping(); kSetChips(kMenu()); }, 400);\n");
      out.write("}\n");
      out.write("\n");
      out.write("function kSend(){\n");
      out.write("  var inp = kEl('kira-input');\n");
      out.write("  var txt = inp.value.trim();\n");
      out.write("  if(!txt) return;\n");
      out.write("  inp.value=''; inp.style.height='';\n");
      out.write("\n");
      out.write("  if(KIRA.state==='esperando_doc'){\n");
      out.write("    kAddMsg(txt,'user'); kSetChips([]);\n");
      out.write("    if(!/^\\d{5,15}$/.test(txt)){ kReply(kT('doc_invalido'),500); return; }\n");
      out.write("    KIRA.state='menu';\n");
      out.write("    kReply(kT('doc_ok').replace(/{d}/g,txt), 600, [{l:kT('volver'),id:'volver_menu'}]);\n");
      out.write("    return;\n");
      out.write("  }\n");
      out.write("\n");
      out.write("  kAddMsg(txt,'user');\n");
      out.write("  var lc = txt.toLowerCase();\n");
      out.write("  if(/cita|appointment|appuntamento|consultar|check|controlla/.test(lc))     kHandle('consultar_cita',txt);\n");
      out.write("  else if(/servicio|service|servizi/.test(lc))                               kHandle('servicios',txt);\n");
      out.write("  else if(/horario|schedule|orario/.test(lc))                                kHandle('horarios',txt);\n");
      out.write("  else if(/contact|contatto|contacto/.test(lc))                              kHandle('contacto',txt);\n");
      out.write("  else if(/como|how|come/.test(lc))                                          kHandle('como_sacar',txt);\n");
      out.write("  else if(/paciente|patient|paziente/.test(lc)&&KIRA.rol!=='PUBLICO')        kHandle('guia_pacientes',txt);\n");
      out.write("  else if(/estado|status|stato/.test(lc)&&KIRA.rol==='MEDICO')               kHandle('estados_cita',txt);\n");
      out.write("  else { kSetChips([]); kReply(kT('no_entiendo'),500,kMenu()); }\n");
      out.write("}\n");
      out.write("\n");
      out.write("function kChangeLang(lang){\n");
      out.write("  KIRA.lang=lang;\n");
      out.write("  document.querySelectorAll('.kira-lang-pill').forEach(function(p){\n");
      out.write("    p.classList.toggle('kira-lang-active', p.getAttribute('data-lang')===lang);\n");
      out.write("  });\n");
      out.write("  kEl('kira-input').placeholder     = kT('placeholder');\n");
      out.write("  kEl('kira-status-txt').textContent = kT('status');\n");
      out.write("  kRestart(true);\n");
      out.write("}\n");
      out.write("\n");
      out.write("function kToggle(){\n");
      out.write("  KIRA.open=!KIRA.open;\n");
      out.write("  kEl('kira-window').classList.toggle('kira-open', KIRA.open);\n");
      out.write("  kEl('kira-btn').classList.toggle('open', KIRA.open);\n");
      out.write("  if(KIRA.open){ kEl('kira-badge').style.display='none'; kEl('kira-input').focus(); }\n");
      out.write("}\n");
      out.write("\n");
      out.write("function kRestart(silent){\n");
      out.write("  kEl('kira-messages').innerHTML=''; kEl('kira-chips').innerHTML='';\n");
      out.write("  KIRA.state='menu';\n");
      out.write("  if(silent){ kAddMsg(kBienvenida(),'bot'); kSetChips(kMenu()); return; }\n");
      out.write("  kShowTyping();\n");
      out.write("  setTimeout(function(){ kHideTyping(); kAddMsg(kBienvenida(),'bot'); kSetChips(kMenu()); }, 800);\n");
      out.write("}\n");
      out.write("\n");
      out.write("/* ── Init: todo en DOMContentLoaded ── */\n");
      out.write("document.addEventListener('DOMContentLoaded', function(){\n");
      out.write("  /* Botón flotante */\n");
      out.write("  kEl('kira-btn').addEventListener('click', kToggle);\n");
      out.write("  /* Header */\n");
      out.write("  kEl('kira-btn-close').addEventListener('click', kToggle);\n");
      out.write("  kEl('kira-btn-restart').addEventListener('click', function(){ kRestart(false); });\n");
      out.write("  /* Lang pills */\n");
      out.write("  document.querySelectorAll('.kira-lang-pill').forEach(function(p){\n");
      out.write("    p.addEventListener('click', function(){ kChangeLang(p.getAttribute('data-lang')); });\n");
      out.write("    p.classList.toggle('kira-lang-active', p.getAttribute('data-lang')===KIRA.lang);\n");
      out.write("  });\n");
      out.write("  /* Input */\n");
      out.write("  kEl('kira-send').addEventListener('click', kSend);\n");
      out.write("  kEl('kira-input').addEventListener('keydown', function(e){\n");
      out.write("    if(e.key==='Enter'&&!e.shiftKey){ e.preventDefault(); kSend(); }\n");
      out.write("  });\n");
      out.write("  kEl('kira-input').addEventListener('input', function(){\n");
      out.write("    this.style.height=''; this.style.height=Math.min(this.scrollHeight,80)+'px';\n");
      out.write("  });\n");
      out.write("  /* Placeholder / status */\n");
      out.write("  kEl('kira-input').placeholder      = kT('placeholder');\n");
      out.write("  kEl('kira-status-txt').textContent = kT('status');\n");
      out.write("  /* Bienvenida */\n");
      out.write("  setTimeout(function(){\n");
      out.write("    kShowTyping();\n");
      out.write("    setTimeout(function(){ kHideTyping(); kAddMsg(kBienvenida(),'bot'); kSetChips(kMenu()); }, 900);\n");
      out.write("  }, 600);\n");
      out.write("});\n");
      out.write("</script>\n");
      out.write("\r\n");
      out.write("</body>\r\n");
      out.write("</html>");
